class Solution:
    def removeInvalidParentheses(self, s: str) -> List[str]:
        def count_mismatch(st):
            left = right = 0
            for ch in st:
                if ch == '(':
                    left += 1
                elif ch == ')':
                    if left:
                        left -= 1
                    else:
                        right += 1
            return left, right

        def dfs(idx, left_rem, right_rem, path, open_count):
            if idx == len(s):
                if left_rem == right_rem == open_count == 0:
                    res.add(path)
                return
            ch = s[idx]
            if ch == '(' and left_rem:
                dfs(idx + 1, left_rem - 1, right_rem, path, open_count)
            if ch == ')' and right_rem:
                dfs(idx + 1, left_rem, right_rem - 1, path, open_count)
            if ch in '()':
                if ch == '(':
                    dfs(idx + 1, left_rem, right_rem, path + ch, open_count + 1)
                elif ch == ')' and open_count:
                    dfs(idx + 1, left_rem, right_rem, path + ch, open_count - 1)
            else:
                dfs(idx + 1, left_rem, right_rem, path + ch, open_count)

        left_del, right_del = count_mismatch(s)
        res = set()
        dfs(0, left_del, right_del, "", 0)
        return list(res) if res else [""]
```
efficiency: HIGH
time complexity: O(2^N)
space complexity: O(N)
